def gcd_l(a: Int, b: Int) -> Int:
    var x = a
    var y = b
    if x < 0:
        x = -x
    if y < 0:
        y = -y
    while y != 0:
        var t = y
        y = x % y
        x = t
    return x

struct Fraction(Copyable, Movable):
    var num: Int
    var den: Int

    def __init__(out self, n: Int, d: Int):
        var g = gcd_l(n, d)
        if g == 0:
            g = 1
        self.num = n // g
        self.den = d // g

    def __add__(self, o: Fraction) -> Fraction:
        return Fraction(self.num * o.den + o.num * self.den, self.den * o.den)

    def __eq__(self, o: Fraction) -> Bool:
        return self.num == o.num and self.den == o.den

