struct Vec3 {
    double x; double y; double z;
    Vec3(double a, double b, double c) : x(a), y(b), z(c) {}
    Vec3 operator+(const Vec3& o) const { return Vec3(x+o.x, y+o.y, z+o.z); }
    Vec3 operator-(const Vec3& o) const { return Vec3(x-o.x, y-o.y, z-o.z); }
    double dot(const Vec3& o) const { return x*o.x + y*o.y + z*o.z; }
};

