    var x: Float64
    var y: Float64
    var z: Float64

    def __add__(self, o: Vec3) -> Vec3:
        return Vec3(self.x + o.x, self.y + o.y, self.z + o.z)

    def __sub__(self, o: Vec3) -> Vec3:
        return Vec3(self.x - o.x, self.y - o.y, self.z - o.z)

    def dot(self, o: Vec3) -> Float64:
        return self.x * o.x + self.y * o.y + self.z * o.z

